INSERT INTO contract_templates (name, category, description, template_content, variables) VALUES 
('Брачный договор', 'family', 'Соглашение о имущественных правах супругов', '<div style="text-align: center; font-weight: bold; font-size: 16pt; margin-bottom: 30px;">БРАЧНЫЙ ДОГОВОР № {{contract_number}}</div><div style="text-align: right; margin-bottom: 20px;">г. {{city}}, {{contract_date}}</div><p style="text-align: justify; line-height: 1.6;">{{spouse1_full_name}}, именуемый(-ая) в дальнейшем "Первый супруг", с одной стороны, и {{spouse2_full_name}}, именуемый(-ая) в дальнейшем "Второй супруг", с другой стороны, заключили настоящий договор о нижеследующем:</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">1. ПРАВОВОЙ РЕЖИМ ИМУЩЕСТВА</div><p style="text-align: justify;">1.1. В отношении {{property_regime_scope}} устанавливается режим {{property_regime}}.</p><table width="100%" style="margin-top: 30px;"><tr valign="top"><td width="50%" style="text-align: center;"><strong>Первый супруг:</strong><br/>{{spouse1_full_name}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{spouse1_signature}}/</td><td width="50%" style="text-align: center;"><strong>Второй супруг:</strong><br/>{{spouse2_full_name}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{spouse2_signature}}/</td></tr></table>', JSON_OBJECT('contract_number', 'Номер договора', 'city', 'Город заключения', 'contract_date', 'Дата заключения', 'spouse1_full_name', 'ФИО первого супруга', 'spouse2_full_name', 'ФИО второго супруга', 'property_regime_scope', 'К какому имуществу применяется режим', 'property_regime', 'Правовой режим', 'spouse1_signature', 'Подпись первого супруга', 'spouse2_signature', 'Подпись второго супруга')),

('Соглашение о разделе имущества', 'family', 'Соглашение супругов о разделе общего имущества', '<div style="text-align: center; font-weight: bold; font-size: 16pt; margin-bottom: 30px;">СОГЛАШЕНИЕ О РАЗДЕЛЕ ОБЩЕГО ИМУЩЕСТВА СУПРУГОВ № {{contract_number}}</div><div style="text-align: right; margin-bottom: 20px;">г. {{city}}, {{contract_date}}</div><p style="text-align: justify; line-height: 1.6;">{{spouse1_full_name}}, именуемый(-ая) в дальнейшем "Первый супруг", с одной стороны, и {{spouse2_full_name}}, именуемый(-ая) в дальнейшем "Второй супруг", с другой стороны, заключили настоящее соглашение о нижеследующем:</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">1. ПРЕДМЕТ СОГЛАШЕНИЯ</div><p style="text-align: justify;">1.1. Стороны договариваются о разделе следующего общего имущества: {{shared_property}}.</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">2. ПОРЯДОК РАЗДЕЛА</div><p style="text-align: justify;">2.1. Первому супругу передается: {{spouse1_property}}.</p><p style="text-align: justify;">2.2. Второму супругу передается: {{spouse2_property}}.</p><table width="100%" style="margin-top: 30px;"><tr valign="top"><td width="50%" style="text-align: center;"><strong>Первый супруг:</strong><br/>{{spouse1_full_name}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{spouse1_signature}}/</td><td width="50%" style="text-align: center;"><strong>Второй супруг:</strong><br/>{{spouse2_full_name}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{spouse2_signature}}/</td></tr></table>', JSON_OBJECT('contract_number', 'Номер договора', 'city', 'Город заключения', 'contract_date', 'Дата заключения', 'spouse1_full_name', 'ФИО первого супруга', 'spouse2_full_name', 'ФИО второго супруга', 'shared_property', 'Описание совместного имущества', 'spouse1_property', 'Имущество первого супруга', 'spouse2_property', 'Имущество второго супруга', 'spouse1_signature', 'Подпись первого супруга', 'spouse2_signature', 'Подпись второго супруга')),

-- НЕДВИЖИМОСТЬ
('Договор купли-продажи недвижимости', 'real_estate', 'Договор купли-продажи недвижимого имущества', '<div style="text-align: center; font-weight: bold; font-size: 16pt; margin-bottom: 30px;">ДОГОВОР КУПЛИ-ПРОДАЖИ НЕДВИЖИМОГО ИМУЩЕСТВА № {{contract_number}}</div><div style="text-align: right; margin-bottom: 20px;">г. {{city}}, {{contract_date}}</div><p style="text-align: justify; line-height: 1.6;">{{seller_full_name}}, именуемый(-ая) в дальнейшем "Продавец", с одной стороны, и {{buyer_full_name}}, именуемый(-ая) в дальнейшем "Покупатель", с другой стороны, заключили настоящий договор о нижеследующем:</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">1. ПРЕДМЕТ ДОГОВОРА</div><p style="text-align: justify;">1.1. Продавец обязуется передать в собственность Покупателю недвижимое имущество: {{property_type}} общей площадью {{total_area}} кв.м, расположенное по адресу: {{property_address}}.</p><p style="text-align: justify;">1.2. Кадастровый номер объекта: {{cadastral_number}}.</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">2. ЦЕНА И ПОРЯДОК РАСЧЕТОВ</div><p style="text-align: justify;">2.1. Цена недвижимого имущества составляет {{sale_price}} ({{sale_price_words}}) рублей.</p><table width="100%" style="margin-top: 30px;"><tr valign="top"><td width="50%" style="text-align: center;"><strong>Продавец:</strong><br/>{{seller_full_name}}<br/>Адрес: {{seller_address}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{seller_signature}}/</td><td width="50%" style="text-align: center;"><strong>Покупатель:</strong><br/>{{buyer_full_name}}<br/>Адрес: {{buyer_address}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{buyer_signature}}/</td></tr></table>', JSON_OBJECT('contract_number', 'Номер договора', 'city', 'Город заключения', 'contract_date', 'Дата заключения', 'seller_full_name', 'ФИО продавца', 'buyer_full_name', 'ФИО покупателя', 'property_type', 'Тип недвижимости', 'total_area', 'Общая площадь', 'property_address', 'Адрес недвижимости', 'cadastral_number', 'Кадастровый номер', 'sale_price', 'Цена продажи', 'sale_price_words', 'Цена прописью', 'seller_address', 'Адрес продавца', 'buyer_address', 'Адрес покупателя', 'seller_signature', 'Подпись продавца', 'buyer_signature', 'Подпись покупателя')),

-- ТРАНСПОРТ
('Договор перевозки грузов', 'transport', 'Договор на перевозку грузов автомобильным транспортом', '<div style="text-align: center; font-weight: bold; font-size: 16pt; margin-bottom: 30px;">ДОГОВОР ПЕРЕВОЗКИ ГРУЗОВ № {{contract_number}}</div><div style="text-align: right; margin-bottom: 20px;">г. {{city}}, {{contract_date}}</div><p style="text-align: justify; line-height: 1.6;">{{carrier_full_name}}, именуемый в дальнейшем "Перевозчик", с одной стороны, и {{shipper_full_name}}, именуемый в дальнейшем "Грузоотправитель", с другой стороны, заключили настоящий договор о нижеследующем:</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">1. ПРЕДМЕТ ДОГОВОРА</div><p style="text-align: justify;">1.1. Перевозчик обязуется перевезти вверенный ему Грузоотправителем груз {{cargo_description}} весом {{cargo_weight}} кг из пункта {{departure_point}} в пункт {{destination_point}}.</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">2. ПРОВОЗНАЯ ПЛАТА</div><p style="text-align: justify;">2.1. Провозная плата составляет {{transportation_fee}} рублей.</p><table width="100%" style="margin-top: 30px;"><tr valign="top"><td width="50%" style="text-align: center;"><strong>Перевозчик:</strong><br/>{{carrier_full_name}}<br/>Адрес: {{carrier_address}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{carrier_signature}}/</td><td width="50%" style="text-align: center;"><strong>Грузоотправитель:</strong><br/>{{shipper_full_name}}<br/>Адрес: {{shipper_address}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{shipper_signature}}/</td></tr></table>', JSON_OBJECT('contract_number', 'Номер договора', 'city', 'Город заключения', 'contract_date', 'Дата заключения', 'carrier_full_name', 'Наименование перевозчика', 'shipper_full_name', 'Наименование грузоотправителя', 'cargo_description', 'Описание груза', 'cargo_weight', 'Вес груза', 'departure_point', 'Пункт отправления', 'destination_point', 'Пункт назначения', 'transportation_fee', 'Провозная плата', 'carrier_address', 'Адрес перевозчика', 'shipper_address', 'Адрес грузоотправителя', 'carrier_signature', 'Подпись перевозчика', 'shipper_signature', 'Подпись грузоотправителя')),

('Договор купли-продажи автомобиля', 'transport', 'Договор купли-продажи транспортного средства', '<div style="text-align: center; font-weight: bold; font-size: 16pt; margin-bottom: 30px;">ДОГОВОР КУПЛИ-ПРОДАЖИ ТРАНСПОРТНОГО СРЕДСТВА № {{contract_number}}</div><div style="text-align: right; margin-bottom: 20px;">г. {{city}}, {{contract_date}}</div><p style="text-align: justify; line-height: 1.6;">{{seller_full_name}}, именуемый(-ая) в дальнейшем "Продавец", с одной стороны, и {{buyer_full_name}}, именуемый(-ая) в дальнейшем "Покупатель", с другой стороны, заключили настоящий договор о нижеследующем:</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">1. ПРЕДМЕТ ДОГОВОРА</div><p style="text-align: justify;">1.1. Продавец передает в собственность Покупателю транспортное средство:<br/>- Марка, модель: {{car_brand_model}}<br/>- Год выпуска: {{manufacture_year}}<br/>- VIN: {{vin_number}}<br/>- Гос. номер: {{license_plate}}</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">2. ЦЕНА</div><p style="text-align: justify;">2.1. Цена транспортного средства составляет {{sale_price}} рублей.</p><table width="100%" style="margin-top: 30px;"><tr valign="top"><td width="50%" style="text-align: center;"><strong>Продавец:</strong><br/>{{seller_full_name}}<br/>Паспорт: {{seller_passport}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{seller_signature}}/</td><td width="50%" style="text-align: center;"><strong>Покупатель:</strong><br/>{{buyer_full_name}}<br/>Паспорт: {{buyer_passport}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{buyer_signature}}/</td></tr></table>', JSON_OBJECT('contract_number', 'Номер договора', 'city', 'Город заключения', 'contract_date', 'Дата заключения', 'seller_full_name', 'ФИО продавца', 'buyer_full_name', 'ФИО покупателя', 'car_brand_model', 'Марка и модель', 'manufacture_year', 'Год выпуска', 'vin_number', 'VIN номер', 'license_plate', 'Гос. номер', 'sale_price', 'Цена продажи', 'seller_passport', 'Паспорт продавца', 'buyer_passport', 'Паспорт покупателя', 'seller_signature', 'Подпись продавца', 'buyer_signature', 'Подпись покупателя')),

-- ГРАЖДАНСКИЕ ДОГОВОРЫ
('Договор дарения', 'civil', 'Договор безвозмездной передачи имущества', '<div style="text-align: center; font-weight: bold; font-size: 16pt; margin-bottom: 30px;">ДОГОВОР ДАРЕНИЯ № {{contract_number}}</div><div style="text-align: right; margin-bottom: 20px;">г. {{city}}, {{contract_date}}</div><p style="text-align: justify; line-height: 1.6;">{{donor_full_name}}, именуемый(-ая) в дальнейшем "Даритель", с одной стороны, и {{recipient_full_name}}, именуемый(-ая) в дальнейшем "Одаряемый", с другой стороны, заключили настоящий договор о нижеследующем:</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">1. ПРЕДМЕТ ДОГОВОРА</div><p style="text-align: justify;">1.1. Даритель безвозмездно передает в собственность Одаряемому {{gift_description}}.</p><p style="text-align: justify;">1.2. Оценочная стоимость передаваемого имущества составляет {{gift_value}} рублей.</p><table width="100%" style="margin-top: 30px;"><tr valign="top"><td width="50%" style="text-align: center;"><strong>Даритель:</strong><br/>{{donor_full_name}}<br/>Адрес: {{donor_address}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{donor_signature}}/</td><td width="50%" style="text-align: center;"><strong>Одаряемый:</strong><br/>{{recipient_full_name}}<br/>Адрес: {{recipient_address}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{recipient_signature}}/</td></tr></table>', JSON_OBJECT('contract_number', 'Номер договора', 'city', 'Город заключения', 'contract_date', 'Дата заключения', 'donor_full_name', 'ФИО дарителя', 'recipient_full_name', 'ФИО одаряемого', 'gift_description', 'Описание дара', 'gift_value', 'Оценочная стоимость', 'donor_address', 'Адрес дарителя', 'recipient_address', 'Адрес одаряемого', 'donor_signature', 'Подпись дарителя', 'recipient_signature', 'Подпись одаряемого')),

-- ИНТЕЛЛЕКТУАЛЬНАЯ СОБСТВЕННОСТЬ
('Лицензионный договор', 'intellectual', 'Договор на использование интеллектуальной собственности', '<div style="text-align: center; font-weight: bold; font-size: 16pt; margin-bottom: 30px;">ЛИЦЕНЗИОННЫЙ ДОГОВОР № {{contract_number}}</div><div style="text-align: right; margin-bottom: 20px;">г. {{city}}, {{contract_date}}</div><p style="text-align: justify; line-height: 1.6;">{{licensor_full_name}}, именуемый(-ая) в дальнейшем "Лицензиар", с одной стороны, и {{licensee_full_name}}, именуемый(-ая) в дальнейшем "Лицензиат", с другой стороны, заключили настоящий договор о нижеследующем:</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">1. ПРЕДМЕТ ДОГОВОРА</div><p style="text-align: justify;">1.1. Лицензиар предоставляет Лицензиату {{license_type}} лицензию на использование {{ip_object}}.</p><p style="text-align: justify;">1.2. Способы использования: {{usage_methods}}.</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">2. ЛИЦЕНЗИОННОЕ ВОЗНАГРАЖДЕНИЕ</div><p style="text-align: justify;">2.1. Размер лицензионного вознаграждения составляет {{royalty_amount}} рублей.</p><table width="100%" style="margin-top: 30px;"><tr valign="top"><td width="50%" style="text-align: center;"><strong>Лицензиар:</strong><br/>{{licensor_full_name}}<br/>Адрес: {{licensor_address}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{licensor_signature}}/</td><td width="50%" style="text-align: center;"><strong>Лицензиат:</strong><br/>{{licensee_full_name}}<br/>Адрес: {{licensee_address}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{licensee_signature}}/</td></tr></table>', JSON_OBJECT('contract_number', 'Номер договора', 'city', 'Город заключения', 'contract_date', 'Дата заключения', 'licensor_full_name', 'Наименование лицензиара', 'licensee_full_name', 'Наименование лицензиата', 'license_type', 'Тип лицензии', 'ip_object', 'Объект интеллектуальной собственности', 'usage_methods', 'Способы использования', 'royalty_amount', 'Размер вознаграждения', 'licensor_address', 'Адрес лицензиара', 'licensee_address', 'Адрес лицензиата', 'licensor_signature', 'Подпись лицензиара', 'licensee_signature', 'Подпись лицензиата')),

-- СТРОИТЕЛЬСТВО
('Договор строительного подряда', 'construction', 'Договор на выполнение строительных работ', '<div style="text-align: center; font-weight: bold; font-size: 16pt; margin-bottom: 30px;">ДОГОВОР СТРОИТЕЛЬНОГО ПОДРЯДА № {{contract_number}}</div><div style="text-align: right; margin-bottom: 20px;">г. {{city}}, {{contract_date}}</div><p style="text-align: justify; line-height: 1.6;">{{customer_full_name}}, именуемый в дальнейшем "Заказчик", с одной стороны, и {{contractor_full_name}}, именуемый в дальнейшем "Подрядчик", с другой стороны, заключили настоящий договор о нижеследующем:</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">1. ПРЕДМЕТ ДОГОВОРА</div><p style="text-align: justify;">1.1. Подрядчик обязуется выполнить следующие строительные работы: {{work_description}} по адресу: {{construction_address}}.</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">2. ЦЕНА РАБОТ</div><p style="text-align: justify;">2.1. Общая стоимость работ составляет {{total_cost}} рублей.</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">3. СРОКИ</div><p style="text-align: justify;">3.1. Начало работ: {{start_date}}.</p><p style="text-align: justify;">3.2. Окончание работ: {{completion_date}}.</p><table width="100%" style="margin-top: 30px;"><tr valign="top"><td width="50%" style="text-align: center;"><strong>Заказчик:</strong><br/>{{customer_full_name}}<br/>Адрес: {{customer_address}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{customer_signature}}/</td><td width="50%" style="text-align: center;"><strong>Подрядчик:</strong><br/>{{contractor_full_name}}<br/>Адрес: {{contractor_address}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{contractor_signature}}/</td></tr></table>', JSON_OBJECT('contract_number', 'Номер договора', 'city', 'Город заключения', 'contract_date', 'Дата заключения', 'customer_full_name', 'Наименование заказчика', 'contractor_full_name', 'Наименование подрядчика', 'work_description', 'Описание работ', 'construction_address', 'Адрес строительства', 'total_cost', 'Общая стоимость', 'start_date', 'Дата начала', 'completion_date', 'Дата окончания', 'customer_address', 'Адрес заказчика', 'contractor_address', 'Адрес подрядчика', 'customer_signature', 'Подпись заказчика', 'contractor_signature', 'Подпись подрядчика')),

-- ДОВЕРИТЕЛЬНОЕ УПРАВЛЕНИЕ
('Договор доверительного управления', 'trust', 'Договор доверительного управления имуществом', '<div style="text-align: center; font-weight: bold; font-size: 16pt; margin-bottom: 30px;">ДОГОВОР ДОВЕРИТЕЛЬНОГО УПРАВЛЕНИЯ ИМУЩЕСТВОМ № {{contract_number}}</div><div style="text-align: right; margin-bottom: 20px;">г. {{city}}, {{contract_date}}</div><p style="text-align: justify; line-height: 1.6;">{{trustor_full_name}}, именуемый(-ая) в дальнейшем "Учредитель управления", с одной стороны, и {{trustee_full_name}}, именуемый(-ая) в дальнейшем "Доверительный управляющий", с другой стороны, заключили настоящий договор о нижеследующем:</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">1. ПРЕДМЕТ ДОГОВОРА</div><p style="text-align: justify;">1.1. Учредитель управления передает Доверительному управляющему на определенный срок имущество: {{property_description}} в доверительное управление.</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">2. ВОЗНАГРАЖДЕНИЕ</div><p style="text-align: justify;">2.1. Размер вознаграждения Доверительного управляющего составляет {{management_fee}}% от стоимости имущества.</p><table width="100%" style="margin-top: 30px;"><tr valign="top"><td width="50%" style="text-align: center;"><strong>Учредитель управления:</strong><br/>{{trustor_full_name}}<br/>Адрес: {{trustor_address}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{trustor_signature}}/</td><td width="50%" style="text-align: center;"><strong>Доверительный управляющий:</strong><br/>{{trustee_full_name}}<br/>Адрес: {{trustee_address}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{trustee_signature}}/</td></tr></table>', JSON_OBJECT('contract_number', 'Номер договора', 'city', 'Город заключения', 'contract_date', 'Дата заключения', 'trustor_full_name', 'Наименование учредителя', 'trustee_full_name', 'Наименование управляющего', 'property_description', 'Описание имущества', 'management_fee', 'Размер вознаграждения', 'trustor_address', 'Адрес учредителя', 'trustee_address', 'Адрес управляющего', 'trustor_signature', 'Подпись учредителя', 'trustee_signature', 'Подпись управляющего')); 